+
+    /// Send data on a stream.
+    pub fn send_data(
+        &mut self,
+        stream_id: u32,
+        data: Bytes,
+        end_stream: bool,
+    ) -> Result<(), H2Error> {
+        let stream = self
+            .streams
+            .get_mut(stream_id)
+            .ok_or_else(|| H2Error::stream(stream_id, ErrorCode::StreamClosed, "stream not found"))?;
