+        let stream = self
+            .streams
+            .get_mut(stream_id)
+            .ok_or_else(|| H2Error::stream(stream_id, ErrorCode::StreamClosed, "stream not found"))?;
+
+        stream.send_headers(end_stream)?;
+
+        self.pending_ops.push_back(PendingOp::Headers {
+            stream_id,
+            headers,
+            end_stream,
+        });
+
+        Ok(())
+    }
+
+    /// Reset a stream.
+    pub fn reset_stream(&mut self, stream_id: u32, error_code: ErrorCode) {
+        if let Some(stream) = self.streams.get_mut(stream_id) {
+            stream.reset(error_code);
+        }
+        self.pending_ops.push_back(PendingOp::RstStream {
+            stream_id,
+            error_code,
