+                Setting::HeaderTableSize(size) => {
+                    self.hpack_encoder.set_max_table_size(*size as usize);
+                }
+                Setting::MaxFrameSize(size) => {
+                    // Update frame codec when we have one
+                    let _ = size;
+                }
+                _ => {}
+            }
+        }
