+        Ok(Some(ReceivedFrame::GoAway {
+            last_stream_id: frame.last_stream_id,
+            error_code: frame.error_code,
+            debug_data: frame.debug_data,
+        }))
+    }
+
+    /// Process WINDOW_UPDATE frame.
+    fn process_window_update(
