+            PendingOp::GoAway {
+                last_stream_id,
+                error_code,
+                debug_data,
+            } => {
+                let mut frame = GoAwayFrame::new(last_stream_id, error_code);
+                frame.debug_data = debug_data;
+                Some(Frame::GoAway(frame))
+            }
+        }
+    }
+
+    /// Check if there are pending frames to send.
+    #[must_use]
+    pub fn has_pending_frames(&self) -> bool {
+        !self.pending_ops.is_empty()
+    }
+
+    /// Send a WINDOW_UPDATE for connection-level flow control.
+    pub fn send_connection_window_update(&mut self, increment: u32) {
+        self.recv_window += increment as i32;
+        self.pending_ops.push_back(PendingOp::WindowUpdate {
+            stream_id: 0,
+            increment,
+        });
+    }
+
+    /// Send a WINDOW_UPDATE for stream-level flow control.
+    pub fn send_stream_window_update(&mut self, stream_id: u32, increment: u32) {
+        if let Some(stream) = self.streams.get_mut(stream_id) {
+            let _ = stream.update_recv_window(increment as i32);
+        }
+        self.pending_ops.push_back(PendingOp::WindowUpdate {
+            stream_id,
+            increment,
+        });
+    }
+
+    /// Prune closed streams.
+    pub fn prune_closed_streams(&mut self) {
+        self.streams.prune_closed();
+    }
+}
+
+/// Received frame event.
+#[derive(Debug)]
+#[allow(missing_docs)]
+pub enum ReceivedFrame {
+    /// Received headers.
+    Headers {
+        stream_id: u32,
+        headers: Vec<Header>,
+        end_stream: bool,
+    },
+    /// Received data.
+    Data {
+        stream_id: u32,
+        data: Bytes,
+        end_stream: bool,
+    },
+    /// Stream was reset.
+    Reset {
+        stream_id: u32,
+        error_code: ErrorCode,
+    },
+    /// Connection is closing.
+    GoAway {
+        last_stream_id: u32,
+        error_code: ErrorCode,
+        debug_data: Bytes,
+    },
+}
+
